// ==================== HTTP Helper ====================
function buildQueryString(params) {
  if (!params || typeof params !== 'object') return ''
  return '?' + Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join('&')
}

async function apiRequest(method, path, body, token) {
  const headers = { 'Content-Type': 'application/json' }
  if (token) headers['Authorization'] = `Bearer ${token}`
  
  // GET/HEAD: convert body object to query string
  let url = `${BASE_URL}${path}`
  const isQueryMethod = ['GET', 'HEAD'].includes(method.toUpperCase())
  if (isQueryMethod && body && typeof body === 'object') {
    url += buildQueryString(body)
  }
  
  const opts = { method, headers }
  if (!isQueryMethod && body) opts.body = JSON.stringify(body)
  const res = await fetch(url, opts)
  const text = await res.text()
  let data
  try { data = JSON.parse(text) } catch { data = { raw: text } }
  return { status: res.status, data }
}

function check(res, label) {
  const code = res?.data?.code ?? res?.data?.Code
  const ok = code != null && (Number(code) === 1 || Number(code) === 200)
  return {
    label,
    ok,
    code,
    msg: res?.data?.msg || res?.data?.message || '',
    data: res?.data?.data,
    status: res?.status,
    raw: JSON.stringify(res?.data).slice(0, 200),
  }
}

