// ==================== Runner ====================
async function runTests() {
  console.log(`\n══════════════════════════════════════════════`)
  console.log(`🔧 SKILL: swap-api-test-generator 已触发`)
  console.log(`   项目: ${new URL(BASE_URL).hostname}:${new URL(BASE_URL).port}`)
  console.log(`   时间: ${new Date().toLocaleString()}`)
  console.log(`══════════════════════════════════════════════\n`)
  console.log(`🚀 Swap Platform API Test`)
  console.log(`   Target: ${BASE_URL}`)
  console.log(`   Time: ${new Date().toLocaleString()}`)
  console.log(`   Cases: ${testCases.length}\n`)
  console.log('─'.repeat(80))

  const results = []
  let pass = 0, fail = 0

  // Phase 1: Auth
  console.log('\n🔐 Phase 1: Auth\n')
  const authCases = testCases.filter(tc => tc.name.includes('登录') || tc.name.includes('登录失败'))
  const otherCases = testCases.filter(tc => !tc.name.includes('登录') && !tc.name.includes('登录失败'))

  for (const tc of authCases) {
    try {
      const r = await tc.fn()
      results.push({ name: tc.name, ...r })
      r.ok ? pass++ : fail++
      console.log(`  ${r.ok ? '✔' : '✘'} [${r.code || 'N/A'}] ${tc.name} ${r.msg ? '- ' + r.msg : ''}`)
    } catch (e) {
      results.push({ name: tc.name, ok: false, code: null, msg: e.message, status: null, raw: '' })
      fail++
      console.log(`  ✘ ${tc.name} - ${e.message}`)
    }
    await sleep(150)
  }

  // Phase 2: Pre-fetch IDs
  console.log('\n🔍 Phase 2: Pre-fetch IDs\n')
  await fetchValidIds()

  // Phase 3: Other cases
  console.log('\n🧪 Phase 3: API Tests\n')
  for (const tc of otherCases) {
    try {
      const r = await tc.fn()
      results.push({ name: tc.name, ...r })
      r.ok ? pass++ : fail++
      console.log(`  ${r.ok ? '✔' : '✘'} [${r.code || 'N/A'}] ${tc.name} ${r.msg ? '- ' + r.msg : ''}`)
    } catch (e) {
      results.push({ name: tc.name, ok: false, code: null, msg: e.message, status: null, raw: '' })
      fail++
      console.log(`  ✘ ${tc.name} - ${e.message}`)
    }
    await sleep(150)
  }

  // ==================== Report ====================
  console.log('\n' + '═'.repeat(80))
  console.log('  Test Report')
  console.log('═'.repeat(80))

  const groups = {}
  for (const r of results) {
    const prefix = r.name.split('：')[0].split('（')[0].split('(')[0].trim()
    if (!groups[prefix]) groups[prefix] = { pass: 0, fail: 0, total: 0 }
    groups[prefix].total++
    if (r.ok) groups[prefix].pass++; else groups[prefix].fail++
  }

  console.log('\n📊 By Module:\n')
  for (const [g, s] of Object.entries(groups)) {
    const mark = s.fail === 0 ? '✅' : '⚠️'
    console.log(`  ${mark} ${g}: ${s.pass}/${s.total}`)
  }

  console.log(`\n  Total: ${results.length} | Pass: ${pass} | Fail: ${fail}`)
  console.log('─'.repeat(80))

  const failed = results.filter(r => !r.ok)
  if (failed.length > 0) {
    console.log('\n❌ Failures:\n')
    for (const r of failed) {
      console.log(`  [${r.name}] HTTP:${r.status} code:${r.code} msg:${r.msg}`)
      console.log(`    ${r.raw.slice(0, 100)}`)
    }
  }

  console.log('\n✅ Passed:\n')
  for (const r of results.filter(r => r.ok)) {
    console.log(`  ✔ ${r.name}`)
  }

  // Save JSON report
  const report = {
    time: new Date().toISOString(),
    baseUrl: BASE_URL,
    summary: { total: results.length, pass, fail },
    groups: Object.fromEntries(
      Object.entries(groups).map(([k, v]) => [k, `${v.pass}/${v.total}`])
    ),
    failed: failed.map(r => ({
      name: r.name, status: r.status, code: r.code, msg: r.msg, raw: r.raw
    })),
    passed: results.filter(r => r.ok).map(r => r.name),
  }

  const reportDir = 'scripts'
  try { mkdirSync(reportDir, { recursive: true }) } catch {}

  const reportPath2 = `${reportDir}/last-report.json`
  writeFileSync(reportPath2, JSON.stringify(report, null, 2), 'utf-8')
  console.log(`\n📄 Report saved: ${reportPath2}`)
  
  const failRate = results.length > 0 ? (fail / results.length * 100).toFixed(1) : 0
  const statusIcon = fail === 0 ? '✅' : (fail <= results.length / 2 ? '⚠️' : '❌')
  console.log(`\n══════════════════════════════════════════════`)
  console.log(`${statusIcon} SKILL: swap-api-test-generator ${fail === 0 ? '完成' : '完成（部分失败）'}`)
  console.log(`   通过: ${pass}/${results.length} (${(100 - failRate)}%) | 失败: ${fail}`)
  console.log(`   报告: ${reportDir}/last-report.md`)
  console.log(`══════════════════════════════════════════════\n`)

  if (!ONCE) {
    console.log('⏳ Re-running in 30s (Ctrl+C to exit)\n')
    setTimeout(runTests, 30000)
  }
}

runTests().catch(e => {
  console.error('Fatal:', e.message)
  process.exit(1)
})
